import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"修炼系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xiulian.md","filePath":"guide/xiulian.md","lastUpdated":null}'),l={name:"guide/xiulian.md"};function i(h,t,o,n,s,b){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="修炼系统" tabindex="-1">修炼系统 <a class="header-anchor" href="#修炼系统" aria-label="Permalink to &quot;修炼系统&quot;">​</a></h1><p>修炼是将灵气转化为修为，逐步突破境界的核心玩法。</p><hr><h2 id="核心参数速查" tabindex="-1">核心参数速查 <a class="header-anchor" href="#核心参数速查" aria-label="Permalink to &quot;核心参数速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>基础灵气恢复</td><td>1.0/秒</td><td>自然恢复速度</td></tr><tr><td>每小阶额外恢复</td><td>+0.5/秒</td><td>每提升1小阶增加</td></tr><tr><td>灵气恢复间隔</td><td>1秒</td><td>每1秒恢复一次</td></tr><tr><td>修炼消耗灵气</td><td>5.0/秒</td><td>修炼时每秒消耗</td></tr><tr><td>灵气转修为比例</td><td>12%</td><td>消耗灵气的12%转为修为</td></tr><tr><td>每小阶所需修为基数</td><td>150.0</td><td>练气1阶→2阶需要150修为</td></tr><tr><td>修炼定身</td><td>✅ 启用</td><td>修炼期间不可移动</td></tr><tr><td>修炼提示间隔</td><td>10秒</td><td>每10秒聊天栏显示进度</td></tr><tr><td>修炼灵气提示方式</td><td>简洁聊天</td><td>简化版提示信息</td></tr></tbody></table><hr><h2 id="灵气系统" tabindex="-1">灵气系统 <a class="header-anchor" href="#灵气系统" aria-label="Permalink to &quot;灵气系统&quot;">​</a></h2><h3 id="灵气是什么" tabindex="-1">灵气是什么？ <a class="header-anchor" href="#灵气是什么" aria-label="Permalink to &quot;灵气是什么？&quot;">​</a></h3><p>灵气是修仙者的核心资源，用于：</p><ul><li>🔄 修炼转化为修为</li><li>⚔️ 释放功法技能</li><li>💊 炼制丹药</li><li>⬆️ 突破境界（消耗当前灵气的一定比例）</li></ul><h3 id="灵气恢复" tabindex="-1">灵气恢复 <a class="header-anchor" href="#灵气恢复" aria-label="Permalink to &quot;灵气恢复&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每秒灵气恢复 = 基础值(1.0) + 当前小阶数 × 0.5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后乘以灵根的灵气恢复倍率：</p><table tabindex="0"><thead><tr><th>灵根</th><th>倍率</th><th>满阶练气(9阶)恢复</th><th>满阶飞升(9阶)恢复</th></tr></thead><tbody><tr><td>无/金/火/土</td><td>×1.0</td><td>5.5/秒</td><td>41.5/秒</td></tr><tr><td>水灵根</td><td>×1.3</td><td>7.15/秒</td><td>53.95/秒</td></tr><tr><td>木灵根</td><td>×1.5</td><td>8.25/秒</td><td>62.25/秒</td></tr><tr><td>天灵根</td><td>×2.0</td><td>11.0/秒</td><td>83.0/秒</td></tr></tbody></table><h3 id="灵气获取方式" tabindex="-1">灵气获取方式 <a class="header-anchor" href="#灵气获取方式" aria-label="Permalink to &quot;灵气获取方式&quot;">​</a></h3><ol><li><strong>自然恢复</strong> — 每秒自动恢复</li><li><strong>击杀怪物</strong> — 伤害的 5% 换算为灵气（<code>击杀灵力伤害换算倍率: 0.05</code>）</li><li><strong>恢复丹</strong> — 丹药直接补充灵气</li><li><strong>灵气潮汐事件</strong> — 天道事件期间恢复翻倍</li></ol><hr><h2 id="修为积累" tabindex="-1">修为积累 <a class="header-anchor" href="#修为积累" aria-label="Permalink to &quot;修为积累&quot;">​</a></h2><h3 id="修炼流程" tabindex="-1">修炼流程 <a class="header-anchor" href="#修炼流程" aria-label="Permalink to &quot;修炼流程&quot;">​</a></h3><ol><li>输入 <code>/xiulian</code> 开始修炼</li><li>进入<strong>定身状态</strong>（不可移动）</li><li>每秒消耗 5 灵气，其中 12% 转化为修为</li><li>每10秒聊天栏显示当前进度</li></ol><h3 id="修炼效率" tabindex="-1">修炼效率 <a class="header-anchor" href="#修炼效率" aria-label="Permalink to &quot;修炼效率&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每秒获得修为 = 5 × 0.12 = 0.6 修为/秒</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>意味着：</p><ul><li>练气1→2阶需要 150 修为 → 修炼 <strong>250秒（约4分钟）</strong></li><li>飞升8→9阶需要更多修为（取决于境界配置）</li></ul><blockquote><p>💡 灵气潮汐事件期间修炼效率 ×1.5！</p></blockquote><h3 id="额外修为消耗" tabindex="-1">额外修为消耗 <a class="header-anchor" href="#额外修为消耗" aria-label="Permalink to &quot;额外修为消耗&quot;">​</a></h3><p>某些操作会消耗修为：</p><ul><li>炼制中等品质以上丹药需要消耗修为</li><li>极品渡劫丹消耗高达 280 修为</li></ul><hr><h2 id="境界属性成长" tabindex="-1">境界属性成长 <a class="header-anchor" href="#境界属性成长" aria-label="Permalink to &quot;境界属性成长&quot;">​</a></h2><h3 id="每小阶属性加成" tabindex="-1">每小阶属性加成 <a class="header-anchor" href="#每小阶属性加成" aria-label="Permalink to &quot;每小阶属性加成&quot;">​</a></h3><p>每提升1个小阶，获得：</p><table tabindex="0"><thead><tr><th>属性</th><th>加成</th></tr></thead><tbody><tr><td>HP上限</td><td>+10</td></tr><tr><td>防御</td><td>+1</td></tr><tr><td>魔力上限</td><td>+1</td></tr></tbody></table><h3 id="每大境界速度加成" tabindex="-1">每大境界速度加成 <a class="header-anchor" href="#每大境界速度加成" aria-label="Permalink to &quot;每大境界速度加成&quot;">​</a></h3><p>每突破1个大境界，速度倍率 <strong>×1.02</strong>（叠加）：</p><table tabindex="0"><thead><tr><th>大境界突破次数</th><th>累计速度倍率</th></tr></thead><tbody><tr><td>1次（练气→筑基）</td><td>×1.02</td></tr><tr><td>3次（→金丹）</td><td>×1.061</td></tr><tr><td>5次（→化神）</td><td>×1.104</td></tr><tr><td>8次（→飞升）</td><td>×1.172</td></tr></tbody></table><hr><h2 id="死亡惩罚" tabindex="-1">死亡惩罚 <a class="header-anchor" href="#死亡惩罚" aria-label="Permalink to &quot;死亡惩罚&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>值</th></tr></thead><tbody><tr><td>死亡扣灵气</td><td>✅ 启用</td></tr><tr><td>扣除比例</td><td>25%</td></tr></tbody></table><blockquote><p>⚠️ 死亡直接扣除当前灵气的四分之一！在高境界拥有大量灵气时死亡代价极大。</p></blockquote><hr><h2 id="聊天前缀" tabindex="-1">聊天前缀 <a class="header-anchor" href="#聊天前缀" aria-label="Permalink to &quot;聊天前缀&quot;">​</a></h2><p>服务器强制所有玩家聊天带有修仙前缀：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>格式: [{Realm}]{Name}: {Message}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>示例：</p><blockquote><p>[练气9阶]玩家小明: 有人一起打Boss吗？ [元婴3阶]大佬: 来了！</p></blockquote><p>这让所有玩家一眼就能看出彼此的修仙境界。</p><hr><h2 id="连续失败保护" tabindex="-1">连续失败保护 <a class="header-anchor" href="#连续失败保护" aria-label="Permalink to &quot;连续失败保护&quot;">​</a></h2><p>突破连续失败时触发保护机制：</p><table tabindex="0"><thead><tr><th>参数</th><th>值</th></tr></thead><tbody><tr><td>保护触发次数</td><td>3次</td></tr><tr><td>触发后获得功德</td><td>+10</td></tr></tbody></table><blockquote><p>🛡️ 连续突破失败3次后自动触发保护，提高下次成功率，同时获得功德补偿。</p></blockquote><hr><h2 id="突破定身" tabindex="-1">突破定身 <a class="header-anchor" href="#突破定身" aria-label="Permalink to &quot;突破定身&quot;">​</a></h2><p>突破时强制定身：</p><table tabindex="0"><thead><tr><th>参数</th><th>值</th></tr></thead><tbody><tr><td>突破定身启用</td><td>✅</td></tr><tr><td>定身时长</td><td>3秒</td></tr></tbody></table><p>突破动画播放期间无法移动，确保突破过程的仪式感。</p><hr><h2 id="功法使用机制" tabindex="-1">功法使用机制 <a class="header-anchor" href="#功法使用机制" aria-label="Permalink to &quot;功法使用机制&quot;">​</a></h2><h3 id="全局冷却" tabindex="-1">全局冷却 <a class="header-anchor" href="#全局冷却" aria-label="Permalink to &quot;全局冷却&quot;">​</a></h3><p>所有功法共享 <strong>5秒</strong> 全局冷却。释放任意功法后需等待5秒才能释放下一个。</p><h3 id="灵气消耗" tabindex="-1">灵气消耗 <a class="header-anchor" href="#灵气消耗" aria-label="Permalink to &quot;灵气消耗&quot;">​</a></h3><p>功法的灵气消耗 = 功法配置值（如灵气弹20、大罗天斩280）。</p><h3 id="击杀灵气" tabindex="-1">击杀灵气 <a class="header-anchor" href="#击杀灵气" aria-label="Permalink to &quot;击杀灵气&quot;">​</a></h3><p>击杀怪物时，造成的总伤害 × 0.05 转化为灵气，提示方式为&quot;简洁聊天&quot;。</p><hr><h2 id="修仙策略" tabindex="-1">修仙策略 <a class="header-anchor" href="#修仙策略" aria-label="Permalink to &quot;修仙策略&quot;">​</a></h2><h3 id="新手期-练气-筑基" tabindex="-1">新手期（练气-筑基） <a class="header-anchor" href="#新手期-练气-筑基" aria-label="Permalink to &quot;新手期（练气-筑基）&quot;">​</a></h3><ol><li>尽快修炼到练气9阶</li><li>击杀克苏鲁之眼解锁筑基</li><li>优先提升小阶数增加灵气恢复速度</li></ol><h3 id="中期-金丹-化神" tabindex="-1">中期（金丹-化神） <a class="header-anchor" href="#中期-金丹-化神" aria-label="Permalink to &quot;中期（金丹-化神）&quot;">​</a></h3><ol><li>渡劫前备好渡劫丹</li><li>利用天道试炼事件突破（+15%成功率）</li><li>保持灵气充足，避免死亡扣25%</li></ol><h3 id="后期-渡劫-飞升" tabindex="-1">后期（渡劫-飞升） <a class="header-anchor" href="#后期-渡劫-飞升" aria-label="Permalink to &quot;后期（渡劫-飞升）&quot;">​</a></h3><ol><li>积累功德提升天道境界（最高+10%突破率）</li><li>囤积极品突破丹（+65%成功率）</li><li>组队击杀高级Boss获取装备</li></ol>',73)])])}const p=a(l,[["render",i]]);export{u as __pageData,p as default};
